-- Tags: no-fasttest
-- no-fasttest: requires the ORC input format, which is not built in fasttest.

-- Regression test for heap buffer overflows / out-of-bounds reads in the native ORC fast decoder
-- (`NativeORCBlockInputFormat`) when a crafted ORC file violates the invariants the decoder assumes
-- about CHAR-typed and dictionary-encoded columns. Before the fix these wrote/read past the bounds of
-- a heap buffer; now they are rejected with INCORRECT_DATA. The crafted files were produced by writing
-- a benign String column with a standard ORC writer and surgically patching the ORC metadata.

SET input_format_orc_use_fast_decoder = 1;
SET input_format_orc_dictionary_as_low_cardinality = 1;

-- A dictionary-encoded CHAR(1) column whose dictionary entry is 2 bytes long: the decoder allocated
-- dict_size * 1 bytes and memcpy'd the 2-byte entry into it.
SELECT * FROM format(ORC, unhex('')) FORMAT Null; -- { serverError INCORRECT_DATA }

-- A non-dictionary CHAR(1) column whose per-row value is longer than the declared width: the decoder
-- reserved numElements * 1 bytes and inserted the longer value without a capacity check.
SELECT * FROM format(ORC, unhex('')) FORMAT Null; -- { serverError INCORRECT_DATA }

-- A dictionary-encoded String column with a per-row dictionary index (255) past the end of the
-- dictionary (size 2): the decoder indexed the dictionary array without a bound check.
SELECT * FROM format(ORC, unhex('')) FORMAT Null; -- { serverError INCORRECT_DATA }
